const base = ($vars.SUPABASE_URL || '').replace(/\/+$/, '');
const key = $vars.SUPABASE_SERVICE_ROLE_KEY;
const resendFrom = $vars.RESEND_FROM || 'onboarding@resend.dev';

if (!base || !key) {
  throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY');
}

function effectiveStatus(status, deadline) {
  if (!deadline) return status;
  const t = new Date(deadline + 'T12:00:00');
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  t.setHours(0, 0, 0, 0);
  const diff = Math.round((t.getTime() - today.getTime()) / 86400000);
  if (diff <= 0) return 'urgent';
  if (diff <= 7) {
    if (status === 'stable') return 'monitor';
    return status;
  }
  return status;
}

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

const profiles = await this.helpers.httpRequest({
  method: 'GET',
  url: base + '/rest/v1/profiles?daily_reminder_enabled=eq.true&select=id,email,daily_reminder_time',
  headers: {
    apikey: key,
    Authorization: 'Bearer ' + key,
    Accept: 'application/json',
  },
  json: true,
});

const list = Array.isArray(profiles) ? profiles : [];
const out = [];

for (const p of list) {
  if (!p.email) continue;

  const cases = await this.helpers.httpRequest({
    method: 'GET',
    url: base + '/rest/v1/cases?user_id=eq.' + p.id + '&select=id,name,client_name,status,deadline',
    headers: {
      apikey: key,
      Authorization: 'Bearer ' + key,
      Accept: 'application/json',
    },
    json: true,
  });

  const arr = Array.isArray(cases) ? cases : [];
  const enriched = arr.map(function(c) { return Object.assign({}, c, { effective: effectiveStatus(c.status, c.deadline) }); });

  const urgent = enriched.filter(function(c) { return c.effective === 'urgent'; });
  const surveiller = enriched.filter(function(c) { return c.effective === 'monitor'; });
  const aVenir = enriched.filter(function(c) { return c.effective === 'stable' && c.deadline; });

  const lines = [];
  lines.push('<h2 style="color:#0F172A;font-family:sans-serif;">Ordo &mdash; Resume du jour</h2>');
  lines.push('<p style="font-family:sans-serif;">Bonjour,</p>');

  if (urgent.length === 0 && surveiller.length === 0 && aVenir.length === 0) {
    lines.push('<p style="font-family:sans-serif;">Aucun delai a signaler aujourd\'hui.</p>');
  } else {
    if (urgent.length) {
      lines.push('<p style="font-family:sans-serif;"><strong style="color:#DC2626;">Urgent (aujourd\'hui ou en retard)</strong></p><ul>');
      for (const c of urgent) {
        lines.push('<li style="font-family:sans-serif;">' + escapeHtml(c.name) + ' &mdash; ' + (c.deadline || '&mdash;') + '</li>');
      }
      lines.push('</ul>');
    }
    if (surveiller.length) {
      lines.push('<p style="font-family:sans-serif;"><strong style="color:#D97706;">A surveiller (moins de 7 jours)</strong></p><ul>');
      for (const c of surveiller) {
        lines.push('<li style="font-family:sans-serif;">' + escapeHtml(c.name) + ' &mdash; ' + (c.deadline || '&mdash;') + '</li>');
      }
      lines.push('</ul>');
    }
    if (aVenir.length) {
      lines.push('<p style="font-family:sans-serif;"><strong>A venir</strong></p><ul>');
      for (const c of aVenir.slice(0, 30)) {
        lines.push('<li style="font-family:sans-serif;">' + escapeHtml(c.name) + ' &mdash; ' + (c.deadline || '&mdash;') + '</li>');
      }
      lines.push('</ul>');
    }
  }

  lines.push('<p style="color:#64748b;font-size:12px;font-family:sans-serif;margin-top:24px;">Ordo &mdash; email automatique</p>');

  out.push({
    json: {
      to: p.email,
      subject: 'Ordo — vos dossiers du jour',
      html: lines.join('\n'),
      resendFrom: resendFrom,
    },
  });
}

return out;
